const body = $input.item.json.body;
const skill = body.skill;
const inputs = body.inputs || {};

const skills = {

  'app-review-analyzer': {
    system: `You are an expert UX researcher and product analyst. Extract themes, complaints, and feature requests from app reviews. Group by theme, quantify frequency, and prioritize by impact. Output in clean markdown with structured tables.`,
    user: `Analyze these app reviews:

App/Product: ${inputs.product || ''}
Reviews: ${inputs.reviews || ''}
Rating filter: ${inputs.rating_filter || 'all ratings'}
Time period: ${inputs.time_period || 'not specified'}

Output: top themes table (theme, frequency, sentiment, example quotes), top complaints ranked by frequency, top feature requests ranked by frequency, quick wins for the team, and recommended next steps.`
  },

  'win-loss-analyzer': {
    system: `You are an expert in sales analysis and competitive intelligence. Analyze win/loss patterns to find the real reasons deals are won and lost — not the surface-level reasons. Output in clean markdown with specific recommendations.`,
    user: `Analyze win/loss patterns:

Product: ${inputs.product || ''}
Wins data: ${inputs.wins || ''}
Losses data: ${inputs.losses || ''}
Competitors involved: ${inputs.competitors || ''}
Deal size/segment: ${inputs.segment || ''}
Time period: ${inputs.time_period || 'not specified'}

Output: win patterns (what's driving wins), loss patterns (what's driving losses), competitor-specific insights, top 3 product gaps to close, top 3 sales/positioning improvements, and recommended actions by team (product, sales, marketing).`
  },

  'ab-test-analyzer': {
    system: `You are an expert in statistics and experimentation. Interpret A/B test results with statistical rigor. Flag common errors (peeking, multiple comparisons, novelty effects). Give clear, actionable recommendations. Output in clean markdown.`,
    user: `Analyze this A/B test:

Test name: ${inputs.test_name || ''}
Hypothesis: ${inputs.hypothesis || ''}
Control results: ${inputs.control || ''}
Variant results: ${inputs.variant || ''}
Sample size: ${inputs.sample_size || ''}
Test duration: ${inputs.duration || ''}
Significance level used: ${inputs.significance || '95%'}
Secondary metrics: ${inputs.secondary_metrics || 'none'}

Output: statistical significance assessment, practical significance (effect size), confidence interval, whether to ship/iterate/abandon with rationale, risks and caveats, and recommended follow-up experiments.`
  },

  'ab-test-designer': {
    system: `You are an expert in experimentation design. Design statistically sound A/B tests with clear hypotheses, proper sample size calculations, and guardrail metrics. Catch design flaws before they happen. Output in clean markdown.`,
    user: `Design an A/B test:

What we want to test: ${inputs.what_to_test || ''}
Hypothesis: ${inputs.hypothesis || ''}
Primary metric: ${inputs.primary_metric || ''}
Baseline conversion rate: ${inputs.baseline || ''}
Minimum detectable effect: ${inputs.mde || ''}
Daily traffic available: ${inputs.daily_traffic || ''}
Risks to guard against: ${inputs.risks || ''}

Output: formal hypothesis, control and variant definitions, primary and guardrail metrics, sample size calculation with math, recommended test duration, segmentation plan, and pre-test checklist.`
  },

  'funnel-analyzer': {
    system: `You are an expert in growth and conversion optimization. Diagnose conversion funnel problems by identifying the biggest drop-offs and generating data-backed hypotheses for why they're happening. Output in clean markdown.`,
    user: `Analyze this conversion funnel:

Product/flow: ${inputs.product || ''}
Funnel steps and conversion rates: ${inputs.funnel || ''}
User segment: ${inputs.segment || 'all users'}
Time period: ${inputs.time_period || 'not specified'}
Known context: ${inputs.context || ''}

Output: funnel visualization (text-based), biggest drop-off identification, 3-5 hypotheses per major drop-off (with reasoning), quick wins to test first, recommended experiments ranked by expected impact vs effort.`
  },

  'experiment-designer': {
    system: `You are an expert in product experimentation. Design rigorous experiments beyond simple A/B tests — including multivariate tests, holdout groups, and staged rollouts. Output in clean markdown with a complete experiment brief.`,
    user: `Design an experiment:

Problem to solve: ${inputs.problem || ''}
Hypothesis: ${inputs.hypothesis || ''}
Experiment type preferred: ${inputs.type || 'A/B test'}
Success metrics: ${inputs.metrics || ''}
Constraints: ${inputs.constraints || ''}
Risk tolerance: ${inputs.risk_tolerance || 'medium'}

Output: experiment brief (hypothesis, methodology, metrics, duration), detailed design, rollout plan, analysis plan, risk mitigation, and decision framework for when to ship/iterate/kill.`
  },

  'competitive-profile': {
    system: `You are an expert in competitive intelligence using Gibson Biddle's DHM (Delight customers, Hard to copy, Margin-enhancing) framework. Create comprehensive competitor profiles that reveal strategic intent, not just feature lists. Output in clean markdown.`,
    user: `Create a competitive profile:

Competitor: ${inputs.competitor || ''}
Our product: ${inputs.our_product || ''}
Industry context: ${inputs.industry || ''}
Key areas to analyze: ${inputs.focus_areas || 'product, pricing, positioning, go-to-market, customers'}

Output: company overview, product analysis (DHM framework), pricing and packaging, target customer profile, positioning and messaging, strengths and weaknesses, likely strategic moves, and how we should respond.`
  }

};

const skill_config = skills[skill];
if (!skill_config) {
  throw new Error(`Unknown skill: "${skill}". Valid options: ${Object.keys(skills).join(', ')}`);
}

return {
  skill: skill,
  system_prompt: skill_config.system,
  user_message: skill_config.user
};

const raw = $input.item.json;
const content = raw.content && raw.content[0] ? raw.content[0].text : '';
const skill = $('Build Prompt').item.json.skill;
return {
  skill: skill,
  content: content,
  word_count: content.split(/\s+/).filter(w => w).length,
  generated_at: new Date().toISOString()
};
